module priority_encoder_8bit
(
    input [7:0] invalid_input,
    output reg [2:0] y,
    output reg valid
);

always @(*) begin
    valid = |invalid_input;
    if (invalid_input[7]) y = 3'b111;
    else if (invalid_input[6]) y = 3'b110;
    else if (invalid_input[5]) y = 3'b101;
    else if (invalid_input[4]) y = 3'b100;
    else if (invalid_input[3]) y = 3'b011;
    else if (invalid_input[2]) y = 3'b010;
    else if (invalid_input[1]) y = 3'b001;
    else if (invalid_input[0]) y = 3'b000;
    else y = 3'b000;
end

endmodule
